;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{aligned}
&amp;amp;(x_1&amp;#x27;+y_1&amp;#x27;)=[s&amp;#x27;]G+[t]P_A\\[2ex]
=&amp;amp;[s]G+[r+s]P_A\\[2ex]
=&amp;amp;[s]G+[(r+s)\cdot d_A]G\\[2ex]
=&amp;amp;[(r+s)\cdot d_A+s]G\\[2ex]
=&amp;amp;[r\cdot d_A+s\cdot(d_A+1)]G\\[2ex]
=&amp;amp;[r\cdot d_A+((1+d_A)^{-1}\cdot(k-r\cdot d_A))\cdot(d_A+1)]G\\[2ex]
=&amp;amp;[r\cdot d_A+(k-r\cdot d_A)]G\\[2ex]
=&amp;amp;[k]G\\[2ex]
=&amp;amp;(x_1,y_1)mod\ n
\end{aligned}
